import re

from django.core import validators
from django.utils.deconstruct import deconstructible
from django.utils.translation import gettext_lazy as _


@deconstructible
class BaseUsernameValidator(validators.RegexValidator):
    regex = r'^[\w.@+-]+$'

    def __init__(self, message, flags):
        self.message = message
        self.flags = flags
        super().__init__(self.regex, self.message, self.flags)


@deconstructible
class ASCIIUsernameValidator(BaseUsernameValidator):
    def __init__(self):
        message = _(
            'Enter a valid username. This value may contain only English letters, '
            'numbers, and @/./+/-/_ characters.'
        )
        flags = re.ASCII
        super().__init__(message, flags)


@deconstructible
class UnicodeUsernameValidator(BaseUsernameValidator):
    def __init__(self):
        message = _(
            'Enter a valid username. This value may contain only letters, '
            'numbers, and @/./+/-/_ characters.'
        )
        flags = 0
        super().__init__(message, flags)

