import inspect
import types
from collections import defaultdict
from itertools import chain

from django.apps import apps
from django.core.checks import Error, Tags, register


@register(Tags.models)
def check_all_models(app_configs=None, **kwargs):
    db_table_models = defaultdict(list)
    indexes = defaultdict(list)
    constraints = defaultdict(list)
    errors = []
    models = apps.get_models() if app_configs is None else chain.from_iterable(
        app_config.get_models() for app_config in app_configs
    )
    for model in models:
        if model._meta.managed and not model._meta.proxy:
            db_table_models[model._meta.db_table].append(model._meta.label)
            if not inspect.ismethod(model.check):
                errors.append(
                    Error(
                        "The '%s.check()' class method is currently overridden by %r."
                        % (model.__name__, model.check),
                        obj=model,
                        id='models.E020'
                    )
                )
            else:
                errors.extend(model.check(**kwargs))
            for model_index in model._meta.indexes:
                indexes[model_index.name].append(model._meta.label)
            for model_constraint in model._meta.constraints:
                constraints[model_constraint.name].append(model._meta.label)
    for db_table, model_labels in db_table_models.items():
        if len(model_labels) != 1:
            errors.append(
                Error(
                    "db_table '%s' is used by multiple models: %s."
                    % (db_table, ', '.join(db_table_models[db_table])),
                    obj=db_table,
                    id='models.E028',
                )
            )
    for index_name, model_labels in indexes.items():
        if len(model_labels) > 1:
            model_labels = set(model_labels)
            errors.append(
                Error(
                    "index name '%s' is not unique %s %s." % (
                        index_name,
                        'for model' if len(model_labels) == 1 else 'amongst models:',
                        ', '.join(sorted(model_labels)),
                    ),
                    id='models.E029' if len(model_labels) == 1 else 'models.E030',
                ),
            )
    for constraint_name, model_labels in constraints.items():
        if len(model_labels) > 1:
            model_labels = set(model_labels)
            errors.append(
                Error(
                    "constraint name '%s' is not unique %s %s." % (
                        constraint_name,
                        'for model' if len(model_labels) == 1 else 'amongst models:',
                        ', '.join(sorted(model_labels)),
                    ),
                    id='models.E031' if len(model_labels) == 1 else 'models.E032',
                ),
            )
    return errors


def _check_lazy_references(apps, ignore=None):
    pending_models = set(apps._pending_operations) - (ignore or set())
    if not pending_models:
        return []

    from django.db.models import signals
    model_signals = {
        signal: name for name, signal in vars(signals).items()
        if isinstance(signal, signals.ModelSignal)
    }

    def extract_operation(obj):
        operation, args, keywords = obj, [], {}
        while hasattr(operation, 'func'):
            args.extend(getattr(operation, 'args', []))
            keywords.update(getattr(operation, 'keywords', {}))
            operation = operation.func
        return operation, args, keywords

    def app_model_error(model_key):
        try:
            apps.get_app_config(model_key[0])
            model_error = "app '%s' doesn't provide model '%s'" % model_key
        except LookupError:
            model_error = "app '%s' isn't installed" % model_key[0]
        return model_error

    known_lazy = {
        ('django.db.models.fields.related', 'resolve_related_class'): lambda model_key, func, args, keywords: Error(
            "The field %(field)s was declared with a lazy reference "
            "to '%(model)s', but %(model_error)s."
            % {
                'model': '.'.join(model_key),
                'field': keywords['field'],
                'model_error': app_model_error(model_key),
            },
            obj=keywords['field'],
            id='fields.E307'
        ),
        ('django.db.models.fields.related', 'set_managed'): None,
        ('django.dispatch.dispatcher', 'connect'): lambda model_key, func, args, keywords: Error(
            "%(receiver)s was connected to the '%(signal)s' signal with a "
            "lazy reference to the sender '%(model)s', but %(model_error)s."
            % {
                'model': '.'.join(model_key),
                'receiver': (
                    "The function '%s'" % args[0].__name__
                    if isinstance(args[0], types.FunctionType)
                    else "Bound method '%s.%s'" % (args[0].__self__.__class__.__name__, args[0].__name__)
                    if isinstance(args[0], types.MethodType)
                    else "An instance of class '%s'" % args[0].__class__.__name__
                ),
                'signal': model_signals.get(func.__self__, 'unknown'),
                'model_error': app_model_error(model_key),
            },
            obj=args[0].__module__,
            id='signals.E001'
        ),
    }

    def build_error(model_key, func, args, keywords):
        key = (func.__module__, func.__name__)
        error_fn = known_lazy.get(key, lambda model_key, func, args, keywords: Error(
            "%(op)s contains a lazy reference to %(model)s, but %(model_error)s."
            % {
                'op': func,
                'model': '.'.join(model_key),
                'model_error': app_model_error(model_key),
            },
            obj=func,
            id='models.E022'
        ))
        return error_fn(model_key, func, args, keywords)

    return sorted(
        filter(None, (
            build_error(model_key, *extract_operation(func))
            for model_key in pending_models
            for func in apps._pending_operations[model_key]
        )),
        key=lambda error: error.msg
    )


@register(Tags.models)
def check_lazy_references(app_configs=None, **kwargs):
    return _check_lazy_references(apps)
